class MagixGallery{constructor(e){this.controller=e.controller,this.itemId=e.itemId,this.containerId=e.containerId||"block-img",this.container=document.getElementById(this.containerId),this.deleteBtn=document.getElementById(e.massDeleteBtnId),this.init()}init(){this.container&&(this.container.addEventListener("click",(e=>{if(e.target.closest(".action-delete-img")){const t=e.target.closest(".action-delete-img");this.handleDelete([t.dataset.id])}if(e.target.closest(".action-set-default")){const t=e.target.closest(".action-set-default");this.handleSetDefault(t.dataset.id)}})),this.container.addEventListener("change",(e=>{e.target.classList.contains("image-checkbox")&&this.updateMassDeleteButton()}))),this.deleteBtn&&this.deleteBtn.addEventListener("click",(()=>{const e=this.container.querySelectorAll(".image-checkbox:checked"),t=Array.from(e).map((e=>e.value));t.length>0&&this.handleDelete(t)})),document.addEventListener("magix:imagesReloaded",(()=>{this.initSortable(),this.updateMassDeleteButton()})),this.reloadGallery()}reloadGallery(){if(!this.container)return;this.container.style.opacity="0.5";const e=(new Date).getTime();fetch(`index.php?controller=${this.controller}&edit=${this.itemId}&action=getImages&t=${e}`).then((e=>e.json())).then((e=>{e.result&&(this.container.innerHTML=e.result,this.container.style.opacity="1",this.initSortable(),this.updateMassDeleteButton())})).catch((e=>console.error("Erreur chargement galerie",e)))}handleDelete(e){if(0===e.length)return;const t=new FormData;e.forEach((e=>t.append("ids[]",e))),t.append("id_pages",this.itemId),fetch(`index.php?controller=${this.controller}&action=processDeleteImage`,{method:"POST",body:t}).then((e=>e.json())).then((e=>{!0===e.success||!0===e.status||"delete_success"===e.type?this.reloadGallery():(console.error("Erreur suppression:",e.message),e.message&&e.message.includes("supprimée")&&this.reloadGallery())})).catch((e=>console.error("Erreur réseau:",e)))}handleSetDefault(e){const t=new FormData;t.append("id_img",e),t.append("edit",this.itemId),fetch(`index.php?controller=${this.controller}&action=processSetDefaultImage`,{method:"POST",body:t}).then((e=>e.json())).then((e=>{!0!==e.success&&!0!==e.status||this.reloadGallery()}))}updateMassDeleteButton(){if(!this.deleteBtn)return;const e=this.container.querySelectorAll(".image-checkbox:checked").length;e>0?(this.deleteBtn.classList.remove("disabled"),this.deleteBtn.innerHTML=`<i class="bi bi-trash me-1"></i> Supprimer (${e})`):(this.deleteBtn.classList.add("disabled"),this.deleteBtn.innerHTML='<i class="bi bi-trash me-1"></i> Supprimer la sélection')}initSortable(){const e=document.getElementById("gallery-grid");e&&"undefined"!=typeof Sortable&&new Sortable(e,{handle:".drag-handle",animation:150,onEnd:()=>this.saveOrder()})}saveOrder(){const e=document.querySelectorAll("#gallery-grid .gallery-item"),t=new FormData;e.forEach((e=>t.append("image[]",e.dataset.id))),fetch(`index.php?controller=${this.controller}&action=processOrderImages`,{method:"POST",body:t})}}